function evaluateCondition(condition, userVal, resourceVal, envVal) {
  const [condKey, condSpec] = Object.entries(condition)[0];
  let actualValue;
  if (condKey.startsWith('user.')) actualValue = userVal[condKey.split('.')[1]];
  else if (condKey.startsWith('resource.')) actualValue = resourceVal[condKey.split('.')[1]];
  else if (condKey.startsWith('env.')) actualValue = envVal[condKey.split('.')[1]];

  const [op, expected] = Object.entries(condSpec)[0];

  if (op === 'equals') {
    if (typeof expected === 'string' && expected.startsWith('resource.')) {
      return actualValue === resourceVal[expected.split('.')[1]];
    }
    return actualValue === expected;
  }
  if (op === 'gte') return typeof actualValue === 'string' ? parseInt(actualValue.replace('>=','')) <= parseInt(expected) : actualValue >= expected;
  if (op === 'in') return expected.includes(actualValue);
  if (op === 'between') return actualValue >= expected[0] && actualValue <= expected[1];
  return false;
}

function matchesRule(rule, request) {
  for (const [key, spec] of Object.entries(rule.conditions)) {
    const condition = { [key]: spec };
    let actualValue;
    if (key.startsWith('user.')) actualValue = request.user[key.split('.')[1]];
    else if (key.startsWith('resource.')) actualValue = request.resource[key.split('.')[1]];
    else if (key.startsWith('env.')) actualValue = request.env[key.split('.')[1]];

    const [op, expected] = Object.entries(spec)[0];

    if (op === 'equals') {
      if (typeof expected === 'string' && expected.includes('.')) {
        const [cat, field] = expected.split('.');
        const refVal = cat === 'resource' ? request.resource[field] : request.user[field];
        if (actualValue !== refVal) return false;
      } else {
        if (actualValue !== expected) return false;
      }
    } else if (op === 'gte') {
      if (typeof expected === 'string' && expected.startsWith('>=')) {
        if (actualValue < parseInt(expected.substring(2))) return false;
      } else {
        if (actualValue < expected) return false;
      }
    } else if (op === 'in') {
      if (!expected.includes(actualValue)) return false;
    } else if (op === 'between') {
      if (actualValue < expected[0] || actualValue > expected[1]) return false;
    }
  }
  return true;
}

function evaluatePolicy(policyData) {
  const { policy, requests } = policyData;
  const decisions = [];

  for (let i = 0; i < requests.length; i++) {
    const request = requests[i];
    let matchedDeny = null;
    let matchedAllow = null;

    for (const rule of policy.rules) {
      if (matchesRule(rule, request)) {
        if (rule.effect === 'deny' && !matchedDeny) {
          matchedDeny = rule;
        } else if (rule.effect === 'allow' && !matchedAllow) {
          matchedAllow = rule;
        }
      }
    }

    if (matchedDeny) {
      decisions.push({
        request: i + 1,
        decision: 'DENY',
        matched_rule: matchedDeny.id,
        reason: `Deny override: ${matchedDeny.id} matched`
      });
    } else if (matchedAllow) {
      decisions.push({
        request: i + 1,
        decision: 'ALLOW',
        matched_rule: matchedAllow.id,
        reason: `${matchedAllow.id} matched`
      });
    } else {
      decisions.push({
        request: i + 1,
        decision: 'DENY',
        matched_rule: 'default',
        reason: 'No matching allow rule; default deny'
      });
    }
  }

  return JSON.stringify({ decisions }, null, 2);
}

const input = JSON.parse(require('fs').readFileSync('/dev/stdin', 'utf8'));
console.log(evaluatePolicy(input));
